const input = $json.body || {};

// extract real scenario text
const scenarioText =
  input.scenario?.brain?.scenario || "No scenario provided";

return {
  scenario: scenarioText,
  history: input.history || [],
  userAnswer: input.userAnswer || "",
  userId: input.userId || "anonymous",
  scenarioId: input.articleId || "default"
};

