let text = $json.output || "";

// تنظيف النص
text = text.replace(/```json/g, '').replace(/```/g, '').trim();

// استخراج JSON
const match = text.match(/\{[\s\S]*\}/);

let data;

try {
  data = JSON.parse(match[0]);
} catch (e) {
  data = {
    reply: "AI response parsing failed. Try again.",
    questions: []
  };
}

return {
  reply: data.reply || "No reply",
  questions: data.questions || []
};
